input.content:
"use client"

import * as React from "react"

import { cn } from "@/registry/bases/base/lib/utils"
import { IconPlaceholder } from "@/app/(create)/components/icon-placeholder"

// ─── Types ────────────────────────────────────────────────────────────────────

type Orientation = "horizontal" | "vertical"

// ─── Stepper Context ──────────────────────────────────────────────────────────

type StepperContextValue = {
  value: string
  onValueChange: (value: string) => void
  orientation: Orientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper />")
  }
  return context
}

// ─── Stepper Item Context ─────────────────────────────────────────────────────

type StepperItemContextValue = {
  value: string
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

type StepperProps = React.ComponentProps<"div"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: Orientation
}

function Stepper({
  value: controlledValue,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [uncontrolledValue, setUncontrolledValue] =
    React.useState(defaultValue)

  const isControlled = controlledValue !== undefined
  const value = isControlled ? controlledValue : uncontrolledValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) setUncontrolledValue(newValue)
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("cn-stepper flex flex-col gap-4", className)}
        {...props}
      >
        {children}
      </div>
    </StepperContext.Provider>
  )
}

// ─── Stepper List ─────────────────────────────────────────────────────────────

function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-list"
      data-orientation={orientation}
      className={cn(
        "cn-stepper-list flex",
        orientation === "horizontal" ? "flex-row items-start" : "flex-col",
        className
      )}
      {...props}
    />
  )
}

// ─── Stepper Item ─────────────────────────────────────────────────────────────

type StepperItemProps = React.ComponentProps<"div"> & {
  value: string
  completed?: boolean
  disabled?: boolean
}

function StepperItem({
  value,
  completed = false,
  disabled = false,
  className,
  children,
  ...props
}: StepperItemProps) {
  const { value: activeValue, orientation } = useStepper()
  const isActive = activeValue === value

  return (
    <StepperItemContext.Provider
      value={{ value, isActive, isCompleted: completed, isDisabled: disabled }}
    >
      <div
        data-slot="stepper-item"
        data-state={isActive ? "active" : "inactive"}
        data-completed={completed || undefined}
        data-disabled={disabled || undefined}
        data-orientation={orientation}
        className={cn(
          "cn-stepper-item flex shrink-0",
          orientation === "horizontal"
            ? "flex-col items-center gap-1.5"
            : "flex-row items-start gap-3",
          className
        )}
        {...props}
      >
        {children}
      </div>
    </StepperItemContext.Provider>
  )
}

// ─── Stepper Trigger ──────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange } = useStepper()
  const { value, isActive, isCompleted, isDisabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={isActive ? "active" : "inactive"}
      data-completed={isCompleted || undefined}
      disabled={isDisabled}
      aria-current={isActive ? "step" : undefined}
      className={cn(
        "cn-stepper-trigger group/stepper-trigger flex cursor-pointer items-center gap-2 outline-none disabled:pointer-events-none disabled:opacity-50",
        className
      )}
      onClick={() => onValueChange(value)}
      {...props}
    >
      {children}
    </button>
  )
}

// ─── Stepper Indicator ────────────────────────────────────────────────────────

function StepperIndicator({
  className,
  children,
  ...props
}: React.ComponentProps<"span">) {
  const { isActive, isCompleted } = useStepperItem()

  return (
    <span
      data-slot="stepper-indicator"
      data-state={isActive ? "active" : "inactive"}
      data-completed={isCompleted || undefined}
      className={cn(
        "cn-stepper-indicator relative flex size-8 shrink-0 items-center justify-center rounded-full border-2 text-sm font-semibold transition-colors",
        isActive &&
          !isCompleted &&
          "border-primary bg-primary text-primary-foreground",
        isCompleted && "border-primary bg-primary text-primary-foreground",
        !isActive &&
          !isCompleted &&
          "border-muted-foreground/30 text-muted-foreground",
        className
      )}
      {...props}
    >
      {isCompleted ? (
        <IconPlaceholder
          lucide="CheckIcon"
          tabler="IconCheck"
          hugeicons="CheckmarkCircle02Icon"
          phosphor="CheckIcon"
          remixicon="RiCheckLine"
          className="size-4"
        />
      ) : (
        children
      )}
    </span>
  )
}

// ─── Stepper Header ───────────────────────────────────────────────────────────

function StepperHeader({ className, ...props }: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="stepper-header"
      className={cn("cn-stepper-header flex flex-col gap-0.5", className)}
      {...props}
    />
  )
}

// ─── Stepper Title ────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { isActive, isCompleted } = useStepperItem()

  return (
    <p
      data-slot="stepper-title"
      data-state={isActive ? "active" : "inactive"}
      data-completed={isCompleted || undefined}
      className={cn(
        "cn-stepper-title text-sm font-medium leading-none",
        isActive || isCompleted ? "text-foreground" : "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── Stepper Description ──────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  const { isActive } = useStepperItem()

  return (
    <p
      data-slot="stepper-description"
      data-state={isActive ? "active" : "inactive"}
      className={cn(
        "cn-stepper-description text-xs",
        isActive ? "text-muted-foreground" : "text-muted-foreground/60",
        className
      )}
      {...props}
    />
  )
}

// ─── Stepper Separator ────────────────────────────────────────────────────────

function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()

  return (
    <div
      data-slot="stepper-separator"
      data-orientation={orientation}
      role="presentation"
      aria-hidden="true"
      className={cn(
        "cn-stepper-separator bg-border transition-colors",
        orientation === "horizontal"
          ? "mt-4 h-px min-w-8 flex-1 self-start"
          : "ml-4 h-6 w-px self-start",
        className
      )}
      {...props}
    />
  )
}

// ─── Stepper Content ──────────────────────────────────────────────────────────

type StepperContentProps = React.ComponentProps<"div"> & {
  value: string
}

function StepperContent({
  value,
  className,
  children,
  ...props
}: StepperContentProps) {
  const { value: activeValue } = useStepper()

  if (activeValue !== value) return null

  return (
    <div
      data-slot="stepper-content"
      data-value={value}
      className={cn("cn-stepper-content", className)}
      {...props}
    >
      {children}
    </div>
  )
}

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperIndicator,
  StepperHeader,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}

