  }
  return context
}

// ─── Stepper Item Context ─────────────────────────────────────────────────────

type StepperItemContextValue = {
  value: string
  isActive: boolean
  isCompleted: boolean
  isDisabled: boolean
}

const StepperItemContext =
  React.createContext<StepperItemContextValue | null>(null)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem />")
  }
  return context
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

type StepperProps = React.ComponentProps<"div"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  orientation?: Orientation
}

function Stepper({
  value: controlledValue,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  children,
  ...props
}: StepperProps) {
  const [uncontrolledValue, setUncontrolledValue] =
    React.useState(defaultValue)

  const isControlled = controlledValue !== undefined
  const value = isControlled ? controlledValue : uncontrolledValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) setUncontrolledValue(newValue)
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("flex flex-col gap-4", className)}
        {...props}
      >
        {children}
