"use client"

import * as React from "react"

import {
  Example,
  ExampleWrapper,
} from "@/registry/bases/base/components/example"
import { Button } from "@/registry/bases/base/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperHeader,
  StepperIndicator,
  StepperItem,
  StepperList,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/bases/base/ui/stepper"

export default function StepperExample() {
  return (
    <ExampleWrapper className="w-full max-w-4xl lg:grid-cols-1 2xl:max-w-4xl 2xl:grid-cols-1">
      <StepperHorizontalBasic />
      <StepperHorizontalWithContent />
      <StepperVerticalBasic />
      <StepperVerticalWithContent />
      <StepperWithDisabled />
    </ExampleWrapper>
  )
}

// ─── Horizontal Basic ─────────────────────────────────────────────────────────

function StepperHorizontalBasic() {
  const [step, setStep] = React.useState("step-2")

  const steps = [
    { value: "step-1", label: "Account", description: "Create account" },
    { value: "step-2", label: "Profile", description: "Set up profile" },
    { value: "step-3", label: "Review", description: "Confirm details" },
  ]

  return (
    <Example title="Horizontal">
      <Stepper
        value={step}
        onValueChange={setStep}
        orientation="horizontal"
        className="w-full max-w-xl"
      >
        <StepperList>
          {steps.map((s, index) => (
            <React.Fragment key={s.value}>
              {index > 0 && <StepperSeparator />}
              <StepperItem
                value={s.value}
                completed={
                  steps.findIndex((x) => x.value === step) > index
                }
              >
                <StepperTrigger>
                  <StepperIndicator>{index + 1}</StepperIndicator>
                </StepperTrigger>
                <StepperHeader className="items-center text-center">
                  <StepperTitle>{s.label}</StepperTitle>
                  <StepperDescription>{s.description}</StepperDescription>
                </StepperHeader>
              </StepperItem>
            </React.Fragment>
          ))}
        </StepperList>
      </Stepper>
    </Example>
  )
}

// ─── Horizontal With Content ──────────────────────────────────────────────────

function StepperHorizontalWithContent() {
  const steps = [
    {
      value: "step-1",
      label: "Account",
      description: "Create your account",
      content:
        "Enter your email address and create a secure password to get started. You can sign up with Google or GitHub for a faster experience.",
    },
    {
      value: "step-2",
      label: "Profile",
      description: "Complete your profile",
      content:
        "Tell us about yourself. Add your name, profile picture, and a short bio so others can get to know you.",
    },
    {
      value: "step-3",
      label: "Confirm",
      description: "Review and submit",
      content:
        "Review the information you've provided. Once everything looks good, submit to activate your account.",
    },
  ]

  const [step, setStep] = React.useState("step-1")
  const [completed, setCompleted] = React.useState<Set<string>>(new Set())

  const currentIndex = steps.findIndex((s) => s.value === step)
  const isLast = currentIndex === steps.length - 1
  const isFirst = currentIndex === 0

  function handleNext() {
    setCompleted((prev) => new Set(prev).add(step))
    if (!isLast) setStep(steps[currentIndex + 1].value)
  }

  function handleBack() {
    if (!isFirst) setStep(steps[currentIndex - 1].value)
  }

  return (
    <Example title="Horizontal with Content">
      <Stepper
        value={step}
        onValueChange={setStep}
        orientation="horizontal"
        className="w-full max-w-xl"
      >
        <StepperList>
          {steps.map((s, index) => (
            <React.Fragment key={s.value}>
              {index > 0 && <StepperSeparator />}
              <StepperItem
                value={s.value}
                completed={completed.has(s.value)}
              >
                <StepperTrigger>
                  <StepperIndicator>{index + 1}</StepperIndicator>
                </StepperTrigger>
                <StepperHeader className="items-center text-center">
                  <StepperTitle>{s.label}</StepperTitle>
                  <StepperDescription>{s.description}</StepperDescription>
                </StepperHeader>
